parameters.jsCode:
const statusCode = $json.statusCode || 0;
const parserType = $json.parser_type || 'generic';
const body = $json.body;
const htmlToText = (input) => String(input || '')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/gi, ' ')
  .replace(/&amp;/gi, '&')
  .replace(/\s+/g, ' ')
  .trim();
const getPriceCandidates = (text) => {
  const matches = text.match(/(?:\$|USD\s?)\d{1,4}(?:[.,]\d{1,2})?/gi) || [];
  return [...new Set(matches)].slice(0, 5);
};
const detectDiscount = (text) => {
  const pct = text.match(/\b\d{1,3}%\s*(?:off|discount)\b/i);
  if (pct) return pct[0];
  const save = text.match(/save\s+(?:\$|USD\s?)\d{1,4}(?:[.,]\d{1,2})?/i);
  if (save) return save[0];
  return '';
};
const parseRss = (xml) => {
  const items = [...String(xml).matchAll(/<item>[\s\S]*?<title><!\[CDATA\[(.*?)\]\]><\/title>[\s\S]*?<link>(.*?)<\/link>[\s\S]*?<description><!\[CDATA\[(.*?)\]\]><\/description>/gi)];
  return items.slice(0, 5).map((m) => ({ title: m[1], link: m[2], text: htmlToText(m[3]) }));
};
const parseReddit = (jsonBody) => {
  const posts = jsonBody?.data?.children || [];
  return posts.slice(0, 8).map((entry) => ({
    title: entry?.data?.title || '',
    link: entry?.data?.url_overridden_by_dest || `https://www.reddit.com${entry?.data?.permalink || ''}`,
    text: `${entry?.data?.selftext || ''} Score:${entry?.data?.score || 0}`,
  }));
};
let parsedItems = [];
if (statusCode >= 400) return [];
if (parserType === 'reddit_json' && typeof body === 'object') {
  parsedItems = parseReddit(body);
} else if ((parserType === 'rss' || /<rss|<feed/i.test(String(body || ''))) && typeof body === 'string') {
  parsedItems = parseRss(body);
} else {
  const text = typeof body === 'string' ? htmlToText(body) : htmlToText(JSON.stringify(body || {}));
  parsedItems = [{ title: `${$json.service} / ${$json.source}`, link: $json.url, text }];
}
const normalizedUrl = ($json.url || '').replace(/\?.*$/, '');
return parsedItems.slice(0, 5).map((item, index) => {
  const text = item.text.slice(0, 4000);
  const prices = getPriceCandidates(`${item.title} ${text}`);
  const priceBefore = prices[0] || '';
  const priceNow = prices[1] || '';
  const discountText = detectDiscount(`${item.title} ${text}`);
  let dealType = 'pricing_signal';
  if (/lifetime/i.test(`${item.title} ${text}`)) dealType = 'lifetime_deal';
  else if (discountText) dealType = 'discount';
  else if (/promo|coupon|code/i.test(`${item.title} ${text}`)) dealType = 'promo_code';
  const contentHash = require('crypto').createHash('sha256').update(`${$json.service}|${$json.source}|${normalizedUrl}|${item.link}|${item.title}|${text.slice(0, 1500)}`).digest('hex');
  return {
    json: {
      run_id: $json.run_id,
      mode: $json.mode,
      current_date: $json.current_date,
      source_id: $json.source_id,
      service: $json.service,
      source: $json.source,
      source_url: item.link || $json.url,
      parent_source_url: $json.url,
      normalized_url: normalizedUrl,
      parser_type: parserType,
      raw_text: text,
      content_hash: contentHash,
      title: item.title || `${$json.service} / ${$json.source}`,
      price_before: priceBefore,
      price_now: priceNow,
      discount_text: discountText,
      deal_type: dealType,
    }
  };
});

const items = $items('Parser Pack Normalize', 0, 0).map((x) => x.json);
const run = $('Create Run').first().json;
return [{ json: {
  run_id: run.id,
  mode: run.mode,
  current_date: new Date().toISOString(),
  raw_items_json: JSON.stringify(items),
  raw_items_count: items.length,
}}];

const agg = $('Aggregate Parsed Items').first().json;
return [{ json: {
  run_id: agg.run_id,
  mode: agg.mode,
  current_date: agg.current_date,
  raw_items_count: agg.raw_items_count,
  raw_items_json: agg.raw_items_json,
  prev_report: $json.prev_report || '',
  active_deals_json: JSON.stringify($json.active_deals || []),
}}];

